// ---- Mini Challenge: Notes App with Room ----

// ---- Complete Notes App ----

// ---- Entity ----
@Entity(tableName = "notes")
data class NoteEntity(
    @PrimaryKey(autoGenerate = true)
    val id: Int = 0,
    val title: String,
    val content: String,
    val timestamp: Long = System.currentTimeMillis(),
    val isFavorite: Boolean = false,
    val color: Int? = null
)

// ---- DAO ----
@Dao
interface NoteDao {
    @Insert
    suspend fun insertNote(note: NoteEntity): Long

    @Query("SELECT * FROM notes ORDER BY timestamp DESC")
    fun getAllNotes(): Flow<List<NoteEntity>>

    @Query("SELECT * FROM notes WHERE isFavorite = 1 ORDER BY timestamp DESC")
    fun getFavoriteNotes(): Flow<List<NoteEntity>>

    @Query("SELECT * FROM notes WHERE title LIKE '%' || :query || '%' OR content LIKE '%' || :query || '%'")
    fun searchNotes(query: String): Flow<List<NoteEntity>>

    @Update
    suspend fun updateNote(note: NoteEntity)

    @Delete
    suspend fun deleteNote(note: NoteEntity)

    @Query("DELETE FROM notes")
    suspend fun deleteAllNotes()
}

// ---- Database ----
@Database(entities = [NoteEntity::class], version = 1)
abstract class NotesDatabase : RoomDatabase() {
    abstract fun noteDao(): NoteDao

    companion object {
        @Volatile
        private var INSTANCE: NotesDatabase? = null

        fun getInstance(context: Context): NotesDatabase {
            return INSTANCE ?: synchronized(this) {
                val instance = Room.databaseBuilder(
                    context.applicationContext,
                    NotesDatabase::class.java,
                    "notes_database"
                )
                    .fallbackToDestructiveMigration()
                    .build()
                INSTANCE = instance
                instance
            }
        }
    }
}

// ---- Repository ----
class NoteRepository(private val dao: NoteDao) {
    fun getAllNotes(): Flow<List<NoteEntity>> = dao.getAllNotes()

    fun getFavoriteNotes(): Flow<List<NoteEntity>> = dao.getFavoriteNotes()

    fun searchNotes(query: String): Flow<List<NoteEntity>> = dao.searchNotes(query)

    suspend fun insertNote(title: String, content: String): Long {
        val note = NoteEntity(title = title, content = content)
        return dao.insertNote(note)
    }

    suspend fun updateNote(note: NoteEntity) = dao.updateNote(note)

    suspend fun toggleFavorite(id: Int) {
        val note = dao.getNoteById(id) ?: return
        dao.updateNote(note.copy(isFavorite = !note.isFavorite))
    }

    suspend fun deleteNote(note: NoteEntity) = dao.deleteNote(note)

    suspend fun deleteAllNotes() = dao.deleteAllNotes()
}

// ---- ViewModel ----
class NotesViewModel(private val repository: NoteRepository) : ViewModel() {
    private val _allNotes = MutableStateFlow<List<NoteEntity>>(emptyList())
    val allNotes: StateFlow<List<NoteEntity>> = _allNotes.asStateFlow()

    private val _favorites = MutableStateFlow<List<NoteEntity>>(emptyList())
    val favorites: StateFlow<List<NoteEntity>> = _favorites.asStateFlow()

    private val _filteredNotes = MutableStateFlow<List<NoteEntity>>(emptyList())
    val filteredNotes: StateFlow<List<NoteEntity>> = _filteredNotes.asStateFlow()

    private val _isLoading = MutableStateFlow(false)
    val isLoading: StateFlow<Boolean> = _isLoading.asStateFlow()

    private val _error = MutableStateFlow<String?>(null)
    val error: StateFlow<String?> = _error.asStateFlow()

    private val _showFavorites = MutableStateFlow(false)
    val showFavorites: StateFlow<Boolean> = _showFavorites.asStateFlow()

    private var searchQuery = ""

    init {
        loadNotes()
    }

    private fun loadNotes() {
        viewModelScope.launch {
            repository.getAllNotes().collect { notes ->
                _allNotes.value = notes
                updateFilteredNotes()
            }
        }

        viewModelScope.launch {
            repository.getFavoriteNotes().collect { notes ->
                _favorites.value = notes
            }
        }
    }

    private fun updateFilteredNotes() {
        val notes = if (_showFavorites.value) {
            _favorites.value
        } else {
            _allNotes.value
        }

        _filteredNotes.value = if (searchQuery.isBlank()) {
            notes
        } else {
            notes.filter { note ->
                note.title.contains(searchQuery, ignoreCase = true) ||
                        note.content.contains(searchQuery, ignoreCase = true)
            }
        }
    }

    fun addNote(title: String, content: String) {
        viewModelScope.launch {
            _isLoading.value = true
            try {
                repository.insertNote(title, content)
                _error.value = null
            } catch (e: Exception) {
                _error.value = "Failed to add note: ${e.message}"
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun updateNote(note: NoteEntity) {
        viewModelScope.launch {
            try {
                repository.updateNote(note)
                _error.value = null
            } catch (e: Exception) {
                _error.value = "Failed to update note: ${e.message}"
            }
        }
    }

    fun toggleFavorite(id: Int) {
        viewModelScope.launch {
            try {
                val note = _allNotes.value.find { it.id == id } ?: return@launch
                repository.updateNote(note.copy(isFavorite = !note.isFavorite))
                _error.value = null
            } catch (e: Exception) {
                _error.value = "Failed to toggle favorite: ${e.message}"
            }
        }
    }

    fun deleteNote(note: NoteEntity) {
        viewModelScope.launch {
            try {
                repository.deleteNote(note)
                _error.value = null
            } catch (e: Exception) {
                _error.value = "Failed to delete note: ${e.message}"
            }
        }
    }

    fun deleteAllNotes() {
        viewModelScope.launch {
            try {
                repository.deleteAllNotes()
                _error.value = null
            } catch (e: Exception) {
                _error.value = "Failed to delete all notes: ${e.message}"
            }
        }
    }

    fun toggleShowFavorites() {
        _showFavorites.value = !_showFavorites.value
        updateFilteredNotes()
    }

    fun searchNotes(query: String) {
        searchQuery = query
        updateFilteredNotes()
    }

    fun clearError() {
        _error.value = null
    }
}

// ---- UI ----
@Composable
fun NotesAppScreen() {
    val context = LocalContext.current
    val db = remember { NotesDatabase.getInstance(context) }
    val repository = remember { NoteRepository(db.noteDao()) }
    val viewModel: NotesViewModel = viewModel(factory = NotesViewModelFactory(repository))

    val notes by viewModel.filteredNotes.collectAsState()
    val isLoading by viewModel.isLoading.collectAsState()
    val error by viewModel.error.collectAsState()
    val showFavorites by viewModel.showFavorites.collectAsState()

    var title by remember { mutableStateOf("") }
    var content by remember { mutableStateOf("") }
    var searchQuery by remember { mutableStateOf("") }
    var showAddDialog by remember { mutableStateOf(false) }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("📝 Notes") },
                actions = {
                    IconButton(onClick = { viewModel.toggleShowFavorites() }) {
                        Icon(
                            if (showFavorites) Icons.Default.Star else Icons.Default.StarBorder,
                            contentDescription = "Favorites"
                        )
                    }
                    IconButton(onClick = { showAddDialog = true }) {
                        Icon(Icons.Default.Add, contentDescription = "Add Note")
                    }
                }
            )
        }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            if (isLoading) {
                Box(modifier = Modifier.fillMaxWidth().height(50.dp), contentAlignment = Alignment.Center) {
                    CircularProgressIndicator()
                }
            }

            if (error != null) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.errorContainer
                    )
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        Text(error ?: "", color = MaterialTheme.colorScheme.onErrorContainer)
                        Button(onClick = { viewModel.clearError() }) { Text("Dismiss") }
                    }
                }
            }

            OutlinedTextField(
                value = searchQuery,
                onValueChange = { searchQuery = it; viewModel.searchNotes(it) },
                label = { Text("Search notes...") },
                leadingIcon = { Icon(Icons.Default.Search, null) },
                modifier = Modifier.fillMaxWidth()
            )

            if (showFavorites) {
                Text("⭐ Favorites", style = MaterialTheme.typography.titleMedium)
            }

            LazyColumn(
                verticalArrangement = Arrangement.spacedBy(8.dp),
                modifier = Modifier.weight(1f)
            ) {
                items(notes) { note ->
                    NoteCard(
                        note = note,
                        onFavoriteToggle = { viewModel.toggleFavorite(note.id) },
                        onDelete = { viewModel.deleteNote(note) }
                    )
                }
            }

            Text(
                text = "${notes.size} notes",
                style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant
            )

            Button(
                onClick = { viewModel.deleteAllNotes() },
                modifier = Modifier.fillMaxWidth(),
                colors = ButtonDefaults.buttonColors(
                    containerColor = MaterialTheme.colorScheme.error
                )
            ) {
                Text("Delete All Notes")
            }
        }
    }

    if (showAddDialog) {
        AddNoteDialog(
            onDismiss = { showAddDialog = false },
            onAdd = { title, content ->
                viewModel.addNote(title, content)
                showAddDialog = false
            }
        )
    }
}

@Composable
fun NoteCard(
    note: NoteEntity,
    onFavoriteToggle: () -> Unit,
    onDelete: () -> Unit
) {
    Card(
        modifier = Modifier.fillMaxWidth(),
        elevation = CardDefaults.cardElevation(2.dp)
    ) {
        Row(
            modifier = Modifier.fillMaxWidth().padding(16.dp),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.Top
        ) {
            Column(modifier = Modifier.weight(1f)) {
                Text(
                    text = note.title,
                    style = MaterialTheme.typography.titleMedium
                )
                Text(
                    text = note.content,
                    style = MaterialTheme.typography.bodyMedium,
                    maxLines = 3,
                    overflow = TextOverflow.Ellipsis
                )
                Text(
                    text = java.text.SimpleDateFormat("MMM dd, yyyy HH:mm", java.util.Locale.getDefault())
                        .format(java.util.Date(note.timestamp)),
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )
            }

            Column(
                verticalArrangement = Arrangement.spacedBy(4.dp)
            ) {
                IconButton(onClick = onFavoriteToggle) {
                    Icon(
                        if (note.isFavorite) Icons.Default.Star else Icons.Default.StarBorder,
                        contentDescription = "Favorite",
                        tint = if (note.isFavorite) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
                IconButton(onClick = onDelete) {
                    Icon(Icons.Default.Delete, contentDescription = "Delete")
                }
            }
        }
    }
}

@Composable
fun AddNoteDialog(
    onDismiss: () -> Unit,
    onAdd: (String, String) -> Unit
) {
    var title by remember { mutableStateOf("") }
    var content by remember { mutableStateOf("") }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text("Add Note") },
        text = {
            Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                OutlinedTextField(
                    value = title,
                    onValueChange = { title = it },
                    label = { Text("Title") },
                    modifier = Modifier.fillMaxWidth()
                )
                OutlinedTextField(
                    value = content,
                    onValueChange = { content = it },
                    label = { Text("Content") },
                    modifier = Modifier.fillMaxWidth(),
                    minLines = 3
                )
            }
        },
        confirmButton = {
            TextButton(
                onClick = { onAdd(title, content) },
                enabled = title.isNotBlank() && content.isNotBlank()
            ) {
                Text("Add")
            }
        },
        dismissButton = {
            TextButton(onClick = onDismiss) {
                Text("Cancel")
            }
        }
    )
}

class NotesViewModelFactory(private val repository: NoteRepository) : ViewModelProvider.Factory {
    override fun <T : ViewModel> create(modelClass: Class<T>): T {
        if (modelClass.isAssignableFrom(NotesViewModel::class.java)) {
            @Suppress("UNCHECKED_CAST")
            return NotesViewModel(repository) as T
        }
        throw IllegalArgumentException("Unknown ViewModel class")
    }
}

